android.extraProguardRules:
-keep class expo.modules.** { *; }
-keep class com.doublesymmetry.** { *; }

# Media3 / ExoPlayer — used by react-native-track-player. Stripping these is the
# most common cause of release-only crashes when audio playback starts.
-keep class androidx.media3.** { *; }
-keep interface androidx.media3.** { *; }
-dontwarn androidx.media3.**

# OkHttp / Okio — RN networking + Media3 DataSource
-keep class okhttp3.** { *; }
-keep interface okhttp3.** { *; }
-keep class okio.** { *; }
-dontwarn okhttp3.**
-dontwarn okio.**

# React Native networking classes accessed reflectively from SslTrustStore.kt
# via Class.forName("com.facebook.react.modules.network.OkHttpClientProvider")
-keep class com.facebook.react.modules.network.OkHttpClientProvider { *; }
-keep class com.facebook.react.modules.network.OkHttpClientFactory { *; }
-keep interface com.facebook.react.modules.network.OkHttpClientFactory { *; }
-keep class com.facebook.react.modules.network.** { *; }

# Hermes — referenced by JSI bridge during init
-keep class com.facebook.hermes.** { *; }
-dontwarn com.facebook.hermes.**

# Kotlin metadata — required for reflective field/method access in some libs
-keep class kotlin.Metadata { *; }
-keepclassmembers class **$WhenMappings { <fields>; }
-keepclassmembers class kotlin.coroutines.SafeContinuation { volatile <fields>; }

# JSSE / SSL — keep our custom TrustManager wiring
-keep class * implements javax.net.ssl.X509TrustManager { *; }
-keep class * implements javax.net.ssl.HostnameVerifier { *; }
